index 3f3f6c6e0d1a..e97db0772c94 100644
--- a/llvm/lib/Analysis/InstructionSimplify.cpp
+++ b/llvm/lib/Analysis/InstructionSimplify.cpp
@@ -4542,9 +4542,55 @@ static Value *simplifySelectWithFCmp(Value *Cond, Value *T, Value *F,

   return nullptr;
 }
+/// Return true if the value is a constant vector where each element is either
+/// poison or true (i1 1). For scalar i1, true if constant true.
+static bool isConstantTrueVector(Value *V, const SimplifyQuery &Q) {
+  if (match(V, m_One()))
+    return true;
+  auto *C = dyn_cast<Constant>(V);
+  if (!C)
+    return false;
+  if (auto *VTy = dyn_cast<FixedVectorType>(C->getType())) {
+    unsigned NumElts = VTy->getNumElements();
+    for (unsigned i = 0; i != NumElts; ++i) {
+      Constant *Elt = C->getAggregateElement(i);
+      if (!Elt)
+        return false;
+      if (!match(Elt, m_One()) && !isa<PoisonValue>(Elt) &&
+          !Q.isUndefValue(Elt))
+        return false;
+    }
+    return true;
+  }
+  return false;
+}
+
+/// Return true if the value is a constant vector where each element is either
+/// poison or false (i1 0). For scalar i1, true if constant false.
+static bool isConstantFalseVector(Value *V, const SimplifyQuery &Q) {
+  if (match(V, m_ZeroInt()))
+    return true;
+  auto *C = dyn_cast<Constant>(V);
+  if (!C)
+    return false;
+  if (auto *VTy = dyn_cast<FixedVectorType>(C->getType())) {
+    unsigned NumElts = VTy->getNumElements();
+    for (unsigned i = 0; i != NumElts; ++i) {
+      Constant *Elt = C->getAggregateElement(i);
+      if (!Elt)
+        return false;
+      if (!match(Elt, m_ZeroInt()) && !isa<PoisonValue>(Elt) &&
+          !Q.isUndefValue(Elt))
+        return false;
+    }
+    return true;
+  }
+  return false;
+}

 /// Given operands for a SelectInst, see if we can fold the result.
 /// If not, this returns null.
+/// If not, this returns null.
 static Value *simplifySelectInst(Value *Cond, Value *TrueVal, Value *FalseVal,
                                  const SimplifyQuery &Q, unsigned MaxRecurse) {
   if (auto *CondC = dyn_cast<Constant>(Cond)) {
@@ -4594,7 +4640,7 @@ static Value *simplifySelectInst(Value *Cond, Value *TrueVal, Value *FalseVal,
       return ConstantInt::getFalse(Cond->getType());

     Value *X, *Y;
-    if (match(FalseVal, m_ZeroInt())) {
+    if (isConstantFalseVector(FalseVal, Q)) {
       // !(X || Y) && X --> false (commuted 2 ways)
       if (match(Cond, m_Not(m_c_LogicalOr(m_Specific(TrueVal), m_Value()))))
         return ConstantInt::getFalse(Cond->getType());
@@ -4607,6 +4653,36 @@ static Value *simplifySelectInst(Value *Cond, Value *TrueVal, Value *FalseVal,
           match(Cond, m_c_LogicalOr(m_Specific(X), m_Specific(Y))))
         return X;
     }
+    // (X && Y) ? true : X --> X
+    // (X && Y) ? true : Y --> Y
+    if (isConstantTrueVector(TrueVal, Q)) {
+      Value *X, *Y;
+      if (match(Cond, m_c_LogicalAnd(m_Value(X), m_Value(Y)))) {
+        if (FalseVal == X) return X;
+        if (FalseVal == Y) return Y;
+      }
+      // X ? true : (X && Y) --> X
+      // Y ? true : (X && Y) --> Y
+      if (match(FalseVal, m_c_LogicalAnd(m_Value(X), m_Value(Y)))) {
+        if (Cond == X) return X;
+        if (Cond == Y) return Y;
+      }
+    }
+    // (X || Y) ? X : false --> X
+    // (X || Y) ? Y : false --> Y
+    if (isConstantFalseVector(FalseVal, Q)) {
+      Value *X, *Y;
+      if (match(Cond, m_c_LogicalOr(m_Value(X), m_Value(Y)))) {
+        if (TrueVal == X) return X;
+        if (TrueVal == Y) return Y;
+      }
+      // X ? (X || Y) : false --> X
+      // Y ? (X || Y) : false --> Y
+      if (match(TrueVal, m_c_LogicalOr(m_Value(X), m_Value(Y)))) {
+        if (Cond == X) return X;
+        if (Cond == Y) return Y;
+      }
+    }
   }

   // select ?, X, X -> X

